// LuceneLexerInit initializes any static state used to implement LuceneLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewLuceneLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func LuceneLexerInit() {
	staticData := &LuceneLexerLexerStaticData
	staticData.once.Do(lucenelexerLexerInit)
}

// NewLuceneLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewLuceneLexer(input antlr.CharStream) *LuceneLexer {
	LuceneLexerInit()
	l := new(LuceneLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
	staticData := &LuceneLexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	l.channelNames = staticData.ChannelNames
	l.modeNames = staticData.ModeNames
	l.RuleNames = staticData.RuleNames
	l.LiteralNames = staticData.LiteralNames
	l.SymbolicNames = staticData.SymbolicNames
	l.GrammarFileName = "LuceneLexer.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

